ts_content = "export interface Book {\n  id: string;\n  title: string;\n  author: string;\n  publisher: string;\n  publishDate: string;\n  price: number;\n  description: string;\n  category: string;\n  coverImage: string;\n  rating: number;\n  reviewCount: number;\n  tags: string[];\n}\n\n"
ts_content += "export const MOCK_BOOKS: Book[] = [\n"

for b in books_data:
    id, title, author, publisher, date, price, desc, cat, isbn, rating, reviews, tags = b
    cover = f"https://covers.openlibrary.org/b/isbn/{isbn}-L.jpg"
    ts_content += "  {\n"
    ts_content += f"    id: \"{id}\",\n"
    ts_content += f"    title: \"{title}\",\n"
    ts_content += f"    author: \"{author}\",\n"
    ts_content += f"    publisher: \"{publisher}\",\n"
    ts_content += f"    publishDate: \"{date}\",\n"
    ts_content += f"    price: {price},\n"
    ts_content += f"    description: \"{desc}\",\n"
    ts_content += f"    category: \"{cat}\",\n"
    ts_content += f"    coverImage: \"{cover}\",\n"
    ts_content += f"    rating: {rating},\n"
    ts_content += f"    reviewCount: {reviews},\n"
    ts_content += f"    tags: {json.dumps(tags, ensure_ascii=False)},\n"
    ts_content += "  },\n"

ts_content += "];\n"

with open("src/data/mockBooks.ts", "w", encoding="utf-8") as f:
    f.write(ts_content)
